"""Stubs for fairseq.tasks.hubert_pretraining.

Pickle references HubertPretrainingConfig and HubertPretrainingTask by
name in the checkpoint cfg.task field. ComfyUI-RVC only reads
`saved_cfg.task.normalize` — a boolean — and our stub's __setstate__
preserves whatever the pickle wrote, so the read works."""


class _Tolerant:
    def __init__(self, *args, **kwargs):
        pass

    def __setstate__(self, state):
        if isinstance(state, dict):
            self.__dict__.update(state)

    def __getattr__(self, name):
        if name.startswith("_"):
            raise AttributeError(name)
        return None

    def __reduce__(self):
        return (self.__class__, ())


class HubertPretrainingConfig(_Tolerant):
    pass


class HubertPretrainingTask(_Tolerant):
    pass
